(501, 5, '钢瓶与灶具间距不足', '钢瓶与灶具间距不足隐患排查', '重大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(502, 5, '储存间通风不良', '储存间通风不良隐患排查', '较大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(503, 5, '储罐区防火间距不足', '储罐区防火间距不足隐患排查', '一般', '《城镇燃气管理条例》', '第三十五条', '燃气经营者应当按照国家有关工程建设标准和安全生产管理的规定，设置燃气设施防腐、绝缘、防雷、降压、隔离等保护装置和安全警示标志，定期进行巡查、检测、维修和维护，确保燃气设施的安全运行。'),
(504, 5, '储罐喷淋降温故障', '储罐喷淋降温故障隐患排查', '重大', '《城镇燃气管理条例》', '第三十六条', '任何单位和个人不得侵占、毁损、擅自拆除或者移动燃气设施，不得毁损、覆盖、涂改、擅自拆除或者移动燃气设施安全警示标志。'),
(505, 5, '残液随意倾倒', '残液随意倾倒隐患排查', '较大', '《城镇燃气设计规范》GB 50028-2006（2020年版）', '第6.3.8条', '燃气管道与建筑物、构筑物、道路、其他管道和地下管沟等之间的水平净距和垂直净距，应符合本规范附录A和附录B的规定。'),
(506, 5, '非法充装站点', '非法充装站点隐患排查', '一般', '《城镇燃气设计规范》GB 50028-2006（2020年版）', '第10.2.21条', '燃气管道与电线和电气设备之间应保持安全间距，并应采取防静电接地措施。'),
(507, 5, '槽车卸车操作不规范', '槽车卸车操作不规范隐患排查', '重大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(508, 5, '场站视频监控故障', '场站视频监控故障隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(509, 5, '管道警示标识缺失', '管道警示标识缺失隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(510, 5, '管线走向标识不清', '管线走向标识不清隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(511, 5, '阀门井盖破损', '阀门井盖破损隐患排查', '较大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(512, 5, '阀门井积水', '阀门井积水隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(513, 5, '阀门井燃气积聚', '阀门井燃气积聚隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(514, 5, '管线交叉间距不足', '管线交叉间距不足隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(515, 5, '穿越建筑物未设套管', '穿越建筑物未设套管隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(516, 5, '未设防雷接地', '未设防雷接地隐患排查', '重大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(517, 5, '防静电接地不良', '防静电接地不良隐患排查', '较大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(518, 5, '法兰跨接缺失', '法兰跨接缺失隐患排查', '一般', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(519, 5, '加气站压缩机故障', '加气站压缩机故障隐患排查', '重大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(520, 5, '加气机计量不准', '加气机计量不准隐患排查', '较大', '《城镇燃气管理条例》', '第三十五条', '燃气经营者应当按照国家有关工程建设标准和安全生产管理的规定，设置燃气设施防腐、绝缘、防雷、降压、隔离等保护装置和安全警示标志，定期进行巡查、检测、维修和维护，确保燃气设施的安全运行。'),
(521, 5, 'CNG储气瓶组超期', 'CNG储气瓶组超期隐患排查', '一般', '《城镇燃气管理条例》', '第三十六条', '任何单位和个人不得侵占、毁损、擅自拆除或者移动燃气设施，不得毁损、覆盖、涂改、擅自拆除或者移动燃气设施安全警示标志。'),
(522, 5, 'LNG储罐真空度下降', 'LNG储罐真空度下降隐患排查', '重大', '《城镇燃气设计规范》GB 50028-2006（2020年版）', '第6.3.8条', '燃气管道与建筑物、构筑物、道路、其他管道和地下管沟等之间的水平净距和垂直净距，应符合本规范附录A和附录B的规定。'),
(523, 5, '站内管线泄漏', '站内管线泄漏隐患排查', '较大', '《城镇燃气设计规范》GB 50028-2006（2020年版）', '第10.2.21条', '燃气管道与电线和电气设备之间应保持安全间距，并应采取防静电接地措施。'),
(524, 5, '卸车软管老化', '卸车软管老化隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(525, 5, '企业管理制度不健全', '企业管理制度不健全隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(526, 5, '用户安全告知不到位', '用户安全告知不到位隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(527, 5, '巡检记录不完整', '巡检记录不完整隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(528, 5, '安全培训未覆盖', '安全培训未覆盖隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(529, 5, '维护保养档案缺失', '维护保养档案缺失隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(530, 5, '应急预案未定期演练', '应急预案未定期演练隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(531, 5, '防腐检测未定期开展', '防腐检测未定期开展隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(532, 5, '智能巡线系统故障', '智能巡线系统故障隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(533, 5, 'SCADA通讯中断', 'SCADA通讯中断隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(534, 5, '泄漏检测定位不足', '泄漏检测定位不足隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(535, 5, '设施改造未办理审批', '设施改造未办理审批隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(536, 5, '竣工验收资料不全', '竣工验收资料不全隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(537, 5, '新建管道未进行强度试验', '新建管道未进行强度试验隐患排查', '重大', '《城镇燃气管理条例》', '第三十五条', '燃气经营者应当按照国家有关工程建设标准和安全生产管理的规定，设置燃气设施防腐、绝缘、防雷、降压、隔离等保护装置和安全警示标志，定期进行巡查、检测、维修和维护，确保燃气设施的安全运行。'),
(538, 6, '食品过期变质', '食品过期变质隐患排查', '较大', '《中华人民共和国食品安全法》', '第四条', '食品生产经营者对其生产经营食品的安全负责。食品生产经营者应当依照法律、法规和食品安全标准从事生产经营活动，保证食品安全，诚信自律，对社会和公众负责，接受社会监督，承担社会责任。'),
(539, 6, '存储温度不达标', '存储温度不达标隐患排查', '一般', '《中华人民共和国食品安全法》', '第三十三条', '食品生产经营应当符合食品安全标准，并符合下列要求：（一）具有与生产经营的食品品种、数量相适应的食品原料处理和食品加工、包装、贮存等场所，保持该场所环境整洁，并与有毒、有害场所以及其他污染源保持规定的距离；（二）具有与生产经营的食品品种、数量相适应的生产经营设备或者设施，有相应的消毒、更衣、盥洗、采光、照明、通风、防腐、防尘、防蝇、防鼠、防虫、洗涤以及处理废水、存放垃圾和废弃物的设备或者设施；（三）有专职或者兼职的食品安全专业技术人员、食品安全管理人员和保证食品安全的规章制度。（四）具有合理的设备布局和工艺流程。'),
(540, 6, '食品交叉污染', '食品交叉污染隐患排查', '重大', '《餐饮服务食品安全操作规范》', '第4.1条', '餐饮服务提供者应当落实食品安全主体责任，配备食品安全管理人员，建立健全食品安全管理制度，定期开展食品安全自查。'),
(541, 6, '添加剂超标', '添加剂超标隐患排查', '较大', '《餐饮服务食品安全操作规范》', '第9.1条', '餐饮服务提供者应当建立食品采购索证索票和进货查验记录制度，采购食品、食品添加剂及食品相关产品时，应当查验供货者的许可证和产品合格证明，并做好记录。'),
(542, 6, '餐具消毒不彻底', '餐具消毒不彻底隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(543, 6, '后厨卫生脏乱差', '后厨卫生脏乱差隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(544, 6, '原料来源不明', '原料来源不明隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(545, 6, '熟食未按规定保存', '熟食未按规定保存隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(546, 6, '生熟食混放', '生熟食混放隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(547, 6, '人员无健康证', '人员无健康证隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(548, 6, '加工场所环境卫生差', '加工场所环境卫生差隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(549, 6, '冷藏冷冻设备温度异常', '冷藏冷冻设备温度异常隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(550, 6, '冷库制冷系统故障', '冷库制冷系统故障隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(551, 6, '冷库门密封条破损', '冷库门密封条破损隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(552, 6, '食品冷链断裂', '食品冷链断裂隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(553, 6, '速冻食品解冻后复冻', '速冻食品解冻后复冻隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(554, 6, '餐饮油烟排放不达标', '餐饮油烟排放不达标隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(555, 6, '排油烟管道积油严重', '排油烟管道积油严重隐患排查', '重大', '《中华人民共和国食品安全法》', '第四条', '食品生产经营者对其生产经营食品的安全负责。食品生产经营者应当依照法律、法规和食品安全标准从事生产经营活动，保证食品安全，诚信自律，对社会和公众负责，接受社会监督，承担社会责任。'),
(556, 6, '厨房灶具漏气', '厨房灶具漏气隐患排查', '较大', '《中华人民共和国食品安全法》', '第三十三条', '食品生产经营应当符合食品安全标准，并符合下列要求：（一）具有与生产经营的食品品种、数量相适应的食品原料处理和食品加工、包装、贮存等场所，保持该场所环境整洁，并与有毒、有害场所以及其他污染源保持规定的距离；（二）具有与生产经营的食品品种、数量相适应的生产经营设备或者设施，有相应的消毒、更衣、盥洗、采光、照明、通风、防腐、防尘、防蝇、防鼠、防虫、洗涤以及处理废水、存放垃圾和废弃物的设备或者设施；（三）有专职或者兼职的食品安全专业技术人员、食品安全管理人员和保证食品安全的规章制度。（四）具有合理的设备布局和工艺流程。'),
(557, 6, '厨房灭火装置失效', '厨房灭火装置失效隐患排查', '一般', '《餐饮服务食品安全操作规范》', '第4.1条', '餐饮服务提供者应当落实食品安全主体责任，配备食品安全管理人员，建立健全食品安全管理制度，定期开展食品安全自查。'),
(558, 6, '厨房电路防水不达标', '厨房电路防水不达标隐患排查', '重大', '《餐饮服务食品安全操作规范》', '第9.1条', '餐饮服务提供者应当建立食品采购索证索票和进货查验记录制度，采购食品、食品添加剂及食品相关产品时，应当查验供货者的许可证和产品合格证明，并做好记录。'),
(559, 6, '食品留样不规范', '食品留样不规范隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(560, 6, '留样记录不全', '留样记录不全隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(561, 6, '留样量不足', '留样量不足隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(562, 6, '留样冷柜温度异常', '留样冷柜温度异常隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(563, 6, '留样保存时间不足', '留样保存时间不足隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(564, 6, '添加剂未专用管理', '添加剂未专用管理隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(565, 6, '使用记录不全', '使用记录不全隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(566, 6, '超范围使用添加剂', '超范围使用添加剂隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(567, 6, '亚硝酸盐使用不当', '亚硝酸盐使用不当隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(568, 6, '农药残留超标', '农药残留超标隐患排查', '较大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(569, 6, '兽药残留超标', '兽药残留超标隐患排查', '一般', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(570, 6, '重金属超标', '重金属超标隐患排查', '重大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(571, 6, '真菌毒素超标', '真菌毒素超标隐患排查', '较大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(572, 6, '致病菌超标', '致病菌超标隐患排查', '一般', '《中华人民共和国食品安全法》', '第四条', '食品生产经营者对其生产经营食品的安全负责。食品生产经营者应当依照法律、法规和食品安全标准从事生产经营活动，保证食品安全，诚信自律，对社会和公众负责，接受社会监督，承担社会责任。'),
(573, 6, '转基因食品未标识', '转基因食品未标识隐患排查', '重大', '《中华人民共和国食品安全法》', '第三十三条', '食品生产经营应当符合食品安全标准，并符合下列要求：（一）具有与生产经营的食品品种、数量相适应的食品原料处理和食品加工、包装、贮存等场所，保持该场所环境整洁，并与有毒、有害场所以及其他污染源保持规定的距离；（二）具有与生产经营的食品品种、数量相适应的生产经营设备或者设施，有相应的消毒、更衣、盥洗、采光、照明、通风、防腐、防尘、防蝇、防鼠、防虫、洗涤以及处理废水、存放垃圾和废弃物的设备或者设施；（三）有专职或者兼职的食品安全专业技术人员、食品安全管理人员和保证食品安全的规章制度。（四）具有合理的设备布局和工艺流程。'),
(574, 6, '过敏原未标注', '过敏原未标注隐患排查', '较大', '《餐饮服务食品安全操作规范》', '第4.1条', '餐饮服务提供者应当落实食品安全主体责任，配备食品安全管理人员，建立健全食品安全管理制度，定期开展食品安全自查。'),
(575, 6, '标签信息不全', '标签信息不全隐患排查', '一般', '《餐饮服务食品安全操作规范》', '第9.1条', '餐饮服务提供者应当建立食品采购索证索票和进货查验记录制度，采购食品、食品添加剂及食品相关产品时，应当查验供货者的许可证和产品合格证明，并做好记录。'),
(576, 6, '食品虚假宣传', '食品虚假宣传隐患排查', '重大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(577, 6, '冒充有机产品', '冒充有机产品隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(578, 6, '饮用水水质不达标', '饮用水水质不达标隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(579, 6, '二次供水水箱未清洗', '二次供水水箱未清洗隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(580, 6, '净水设备滤芯未更换', '净水设备滤芯未更换隐患排查', '较大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(581, 6, '直饮水机维护不到位', '直饮水机维护不到位隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(582, 6, '餐饮具集中消毒不达标', '餐饮具集中消毒不达标隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(583, 6, '一次性餐具不合格', '一次性餐具不合格隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(584, 6, '包装材料释放有害物质', '包装材料释放有害物质隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(585, 6, '塑料餐具耐温等级不符', '塑料餐具耐温等级不符隐患排查', '重大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(586, 6, '生熟不分', '生熟不分隐患排查', '较大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(587, 6, '加工过程交叉污染', '加工过程交叉污染隐患排查', '一般', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(588, 6, '食材清洗不彻底', '食材清洗不彻底隐患排查', '重大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(589, 6, '案板刀具生熟混用', '案板刀具生熟混用隐患排查', '较大', '《中华人民共和国食品安全法》', '第四条', '食品生产经营者对其生产经营食品的安全负责。食品生产经营者应当依照法律、法规和食品安全标准从事生产经营活动，保证食品安全，诚信自律，对社会和公众负责，接受社会监督，承担社会责任。'),
(590, 6, '烹饪温度未达标', '烹饪温度未达标隐患排查', '一般', '《中华人民共和国食品安全法》', '第三十三条', '食品生产经营应当符合食品安全标准，并符合下列要求：（一）具有与生产经营的食品品种、数量相适应的食品原料处理和食品加工、包装、贮存等场所，保持该场所环境整洁，并与有毒、有害场所以及其他污染源保持规定的距离；（二）具有与生产经营的食品品种、数量相适应的生产经营设备或者设施，有相应的消毒、更衣、盥洗、采光、照明、通风、防腐、防尘、防蝇、防鼠、防虫、洗涤以及处理废水、存放垃圾和废弃物的设备或者设施；（三）有专职或者兼职的食品安全专业技术人员、食品安全管理人员和保证食品安全的规章制度。（四）具有合理的设备布局和工艺流程。'),
(591, 6, '烹饪后放置时间过长', '烹饪后放置时间过长隐患排查', '重大', '《餐饮服务食品安全操作规范》', '第4.1条', '餐饮服务提供者应当落实食品安全主体责任，配备食品安全管理人员，建立健全食品安全管理制度，定期开展食品安全自查。'),
(592, 6, '盒饭配送温度不达标', '盒饭配送温度不达标隐患排查', '较大', '《餐饮服务食品安全操作规范》', '第9.1条', '餐饮服务提供者应当建立食品采购索证索票和进货查验记录制度，采购食品、食品添加剂及食品相关产品时，应当查验供货者的许可证和产品合格证明，并做好记录。'),
(593, 6, '外卖包装破损', '外卖包装破损隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(594, 6, '从业人员手部有伤口', '从业人员手部有伤口隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(595, 6, '穿戴不规范', '穿戴不规范隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(596, 6, '个人卫生差', '个人卫生差隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(597, 6, '带病上岗', '带病上岗隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(598, 6, '采购索证索票不齐', '采购索证索票不齐隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(599, 6, '进货查验记录不全', '进货查验记录不全隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(600, 6, '供应商资质过期', '供应商资质过期隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(601, 6, '原料未分区存放', '原料未分区存放隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(602, 6, '鼠害防治不到位', '鼠害防治不到位隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(603, 6, '蟑螂防治不到位', '蟑螂防治不到位隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(604, 6, '蚊虫防治不到位', '蚊虫防治不到位隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(605, 6, '防鼠防虫设施损坏', '防鼠防虫设施损坏隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(606, 6, '废弃油脂处理不规范', '废弃油脂处理不规范隐患排查', '重大', '《中华人民共和国食品安全法》', '第四条', '食品生产经营者对其生产经营食品的安全负责。食品生产经营者应当依照法律、法规和食品安全标准从事生产经营活动，保证食品安全，诚信自律，对社会和公众负责，接受社会监督，承担社会责任。'),
(607, 6, '餐厨垃圾未分类收集', '餐厨垃圾未分类收集隐患排查', '较大', '《中华人民共和国食品安全法》', '第三十三条', '食品生产经营应当符合食品安全标准，并符合下列要求：（一）具有与生产经营的食品品种、数量相适应的食品原料处理和食品加工、包装、贮存等场所，保持该场所环境整洁，并与有毒、有害场所以及其他污染源保持规定的距离；（二）具有与生产经营的食品品种、数量相适应的生产经营设备或者设施，有相应的消毒、更衣、盥洗、采光、照明、通风、防腐、防尘、防蝇、防鼠、防虫、洗涤以及处理废水、存放垃圾和废弃物的设备或者设施；（三）有专职或者兼职的食品安全专业技术人员、食品安全管理人员和保证食品安全的规章制度。（四）具有合理的设备布局和工艺流程。'),
(608, 6, '清运不及时', '清运不及时隐患排查', '一般', '《餐饮服务食品安全操作规范》', '第4.1条', '餐饮服务提供者应当落实食品安全主体责任，配备食品安全管理人员，建立健全食品安全管理制度，定期开展食品安全自查。'),
(609, 6, '存放容器不洁', '存放容器不洁隐患排查', '重大', '《餐饮服务食品安全操作规范》', '第9.1条', '餐饮服务提供者应当建立食品采购索证索票和进货查验记录制度，采购食品、食品添加剂及食品相关产品时，应当查验供货者的许可证和产品合格证明，并做好记录。'),
(610, 6, '管理制度不健全', '管理制度不健全隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(611, 6, '管理人员未配备', '管理人员未配备隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(612, 6, '自查未开展', '自查未开展隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(613, 6, '培训不到位', '培训不到位隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(614, 6, '校园食堂风险防控不力', '校园食堂风险防控不力隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(615, 6, '集体用餐配送单位资质不全', '集体用餐配送单位资质不全隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(616, 6, '农村聚餐监管缺失', '农村聚餐监管缺失隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(617, 6, '校长负责制未落实', '校长负责制未落实隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(618, 6, '企业食堂无许可证', '企业食堂无许可证隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(619, 6, '摊贩无证经营', '摊贩无证经营隐患排查', '较大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(620, 6, '应急预案不完善', '应急预案不完善隐患排查', '一般', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(621, 6, '事件报告不及时', '事件报告不及时隐患排查', '重大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(622, 6, '召回制度执行不到位', '召回制度执行不到位隐患排查', '较大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(623, 6, '日常巡查频次不足', '日常巡查频次不足隐患排查', '一般', '《中华人民共和国食品安全法》', '第四条', '食品生产经营者对其生产经营食品的安全负责。食品生产经营者应当依照法律、法规和食品安全标准从事生产经营活动，保证食品安全，诚信自律，对社会和公众负责，接受社会监督，承担社会责任。'),
(624, 6, '抽检覆盖率不够', '抽检覆盖率不够隐患排查', '重大', '《中华人民共和国食品安全法》', '第三十三条', '食品生产经营应当符合食品安全标准，并符合下列要求：（一）具有与生产经营的食品品种、数量相适应的食品原料处理和食品加工、包装、贮存等场所，保持该场所环境整洁，并与有毒、有害场所以及其他污染源保持规定的距离；（二）具有与生产经营的食品品种、数量相适应的生产经营设备或者设施，有相应的消毒、更衣、盥洗、采光、照明、通风、防腐、防尘、防蝇、防鼠、防虫、洗涤以及处理废水、存放垃圾和废弃物的设备或者设施；（三）有专职或者兼职的食品安全专业技术人员、食品安全管理人员和保证食品安全的规章制度。（四）具有合理的设备布局和工艺流程。'),
(625, 6, '信息公开不及时', '信息公开不及时隐患排查', '较大', '《餐饮服务食品安全操作规范》', '第4.1条', '餐饮服务提供者应当落实食品安全主体责任，配备食品安全管理人员，建立健全食品安全管理制度，定期开展食品安全自查。'),
(626, 7, '工业废水超标排放', '工业废水超标排放隐患排查', '一般', '《中华人民共和国环境保护法》', '第四十二条', '排放污染物的企业事业单位和其他生产经营者，应当采取措施，防治在生产建设或者其他活动中产生的废气、废水、废渣、医疗废物、粉尘、恶臭气体、放射性物质以及噪声、振动、光辐射、电磁辐射等对环境的污染和危害。排放污染物的企业事业单位和其他生产经营者，应当按照国家有关规定缴纳排污费。'),
(627, 7, '生活污水直排', '生活污水直排隐患排查', '重大', '《中华人民共和国水污染防治法》', '第十条', '排放水污染物，不得超过国家或者地方规定的水污染物排放标准和重点水污染物排放总量控制指标。'),
(628, 7, '河流水质污染', '河流水质污染隐患排查', '较大', '《中华人民共和国大气污染防治法》', '第十八条', '企业事业单位和其他生产经营者建设对大气环境有影响的项目，应当依法进行环境影响评价、公开环境影响评价文件。'),
(629, 7, '地下水污染', '地下水污染隐患排查', '一般', '《中华人民共和国固体废物污染环境防治法》', '第十七条', '建设产生、贮存、利用、处置固体废物的项目，应当依法进行环境影响评价，并遵守国家有关建设项目环境保护管理的规定。'),
(630, 7, '饮用水源地污染', '饮用水源地污染隐患排查', '重大', '《危险废物贮存污染控制标准》GB 18597-2023', '第4.1条', '产生危险废物的单位应当建立健全危险废物管理制度，按照国家有关规定制定危险废物管理计划，并采取有效措施防止危险废物污染环境。'),
(631, 7, '黑臭水体', '黑臭水体隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(632, 7, '废气排放超标', '废气排放超标隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(633, 7, '烟尘排放超标', '烟尘排放超标隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(634, 7, 'VOCs排放超标', 'VOCs排放超标隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(635, 7, '恶臭气体排放', '恶臭气体排放隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(636, 7, '粉尘无组织排放', '粉尘无组织排放隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(637, 7, '危废非法倾倒', '危废非法倾倒隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(638, 7, '危废混入一般废物', '危废混入一般废物隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(639, 7, '危废贮存不规范', '危废贮存不规范隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(640, 7, '危废容器破损', '危废容器破损隐患排查', '较大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(641, 7, '危废标识缺失', '危废标识缺失隐患排查', '一般', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(642, 7, '危废超期贮存', '危废超期贮存隐患排查', '重大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(643, 7, '危废转移联单不规范', '危废转移联单不规范隐患排查', '较大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(644, 7, '危废运输泄漏', '危废运输泄漏隐患排查', '一般', '《中华人民共和国环境保护法》', '第四十二条', '排放污染物的企业事业单位和其他生产经营者，应当采取措施，防治在生产建设或者其他活动中产生的废气、废水、废渣、医疗废物、粉尘、恶臭气体、放射性物质以及噪声、振动、光辐射、电磁辐射等对环境的污染和危害。排放污染物的企业事业单位和其他生产经营者，应当按照国家有关规定缴纳排污费。'),
(645, 7, '医疗废物混入生活垃圾', '医疗废物混入生活垃圾隐患排查', '重大', '《中华人民共和国水污染防治法》', '第十条', '排放水污染物，不得超过国家或者地方规定的水污染物排放标准和重点水污染物排放总量控制指标。'),
(646, 7, '医废包装破损', '医废包装破损隐患排查', '较大', '《中华人民共和国大气污染防治法》', '第十八条', '企业事业单位和其他生产经营者建设对大气环境有影响的项目，应当依法进行环境影响评价、公开环境影响评价文件。'),
(647, 7, '医废暂存间不合规', '医废暂存间不合规隐患排查', '一般', '《中华人民共和国固体废物污染环境防治法》', '第十七条', '建设产生、贮存、利用、处置固体废物的项目，应当依法进行环境影响评价，并遵守国家有关建设项目环境保护管理的规定。'),
(648, 7, '医废登记记录不全', '医废登记记录不全隐患排查', '重大', '《危险废物贮存污染控制标准》GB 18597-2023', '第4.1条', '产生危险废物的单位应当建立健全危险废物管理制度，按照国家有关规定制定危险废物管理计划，并采取有效措施防止危险废物污染环境。'),
(649, 7, '固废随意堆放', '固废随意堆放隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(650, 7, '工业固废未分类', '工业固废未分类隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(651, 7, '建筑垃圾乱堆放', '建筑垃圾乱堆放隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(652, 7, '垃圾未分类收集', '垃圾未分类收集隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(653, 7, '填埋场渗滤液泄漏', '填埋场渗滤液泄漏隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(654, 7, '土壤污染', '土壤污染隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(655, 7, '重金属污染土壤', '重金属污染土壤隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(656, 7, '石油烃污染土壤', '石油烃污染土壤隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(657, 7, 'POPs污染土壤', 'POPs污染土壤隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(658, 7, '污染地块修复不到位', '污染地块修复不到位隐患排查', '较大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(659, 7, '噪声超标', '噪声超标隐患排查', '一般', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(660, 7, '建筑施工噪声超标', '建筑施工噪声超标隐患排查', '重大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(661, 7, '工业生产噪声超标', '工业生产噪声超标隐患排查', '较大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(662, 7, '社会生活噪声超标', '社会生活噪声超标隐患排查', '一般', '《中华人民共和国环境保护法》', '第四十二条', '排放污染物的企业事业单位和其他生产经营者，应当采取措施，防治在生产建设或者其他活动中产生的废气、废水、废渣、医疗废物、粉尘、恶臭气体、放射性物质以及噪声、振动、光辐射、电磁辐射等对环境的污染和危害。排放污染物的企业事业单位和其他生产经营者，应当按照国家有关规定缴纳排污费。'),
(663, 7, '交通运输噪声超标', '交通运输噪声超标隐患排查', '重大', '《中华人民共和国水污染防治法》', '第十条', '排放水污染物，不得超过国家或者地方规定的水污染物排放标准和重点水污染物排放总量控制指标。'),
(664, 7, '光污染', '光污染隐患排查', '较大', '《中华人民共和国大气污染防治法》', '第十八条', '企业事业单位和其他生产经营者建设对大气环境有影响的项目，应当依法进行环境影响评价、公开环境影响评价文件。'),
(665, 7, '幕墙反射光扰民', '幕墙反射光扰民隐患排查', '一般', '《中华人民共和国固体废物污染环境防治法》', '第十七条', '建设产生、贮存、利用、处置固体废物的项目，应当依法进行环境影响评价，并遵守国家有关建设项目环境保护管理的规定。'),
(666, 7, '夜间灯光扰民', '夜间灯光扰民隐患排查', '重大', '《危险废物贮存污染控制标准》GB 18597-2023', '第4.1条', '产生危险废物的单位应当建立健全危险废物管理制度，按照国家有关规定制定危险废物管理计划，并采取有效措施防止危险废物污染环境。'),
(667, 7, '景观照明影响休息', '景观照明影响休息隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(668, 7, '恶臭污染', '恶臭污染隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(669, 7, '垃圾转运站恶臭', '垃圾转运站恶臭隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
