(671, 7, '养殖场恶臭', '养殖场恶臭隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(672, 7, '化工厂异味', '化工厂异味隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(673, 7, '放射性污染', '放射性污染隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(674, 7, '放射源丢失', '放射源丢失隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(675, 7, '放射性废物处置不当', '放射性废物处置不当隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(676, 7, '放射性物质运输泄漏', '放射性物质运输泄漏隐患排查', '较大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(677, 7, '辐照装置防护不足', '辐照装置防护不足隐患排查', '一般', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(678, 7, '化学泄漏', '化学泄漏隐患排查', '重大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(679, 7, '储罐泄漏', '储罐泄漏隐患排查', '较大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(680, 7, '化学品运输车泄漏', '化学品运输车泄漏隐患排查', '一般', '《中华人民共和国环境保护法》', '第四十二条', '排放污染物的企业事业单位和其他生产经营者，应当采取措施，防治在生产建设或者其他活动中产生的废气、废水、废渣、医疗废物、粉尘、恶臭气体、放射性物质以及噪声、振动、光辐射、电磁辐射等对环境的污染和危害。排放污染物的企业事业单位和其他生产经营者，应当按照国家有关规定缴纳排污费。'),
(681, 7, '管道破裂', '管道破裂隐患排查', '重大', '《中华人民共和国水污染防治法》', '第十条', '排放水污染物，不得超过国家或者地方规定的水污染物排放标准和重点水污染物排放总量控制指标。'),
(682, 7, '实验室废液乱排', '实验室废液乱排隐患排查', '较大', '《中华人民共和国大气污染防治法》', '第十八条', '企业事业单位和其他生产经营者建设对大气环境有影响的项目，应当依法进行环境影响评价、公开环境影响评价文件。'),
(683, 7, '排污口设置不规范', '排污口设置不规范隐患排查', '一般', '《中华人民共和国固体废物污染环境防治法》', '第十七条', '建设产生、贮存、利用、处置固体废物的项目，应当依法进行环境影响评价，并遵守国家有关建设项目环境保护管理的规定。'),
(684, 7, '暗管偷排', '暗管偷排隐患排查', '重大', '《危险废物贮存污染控制标准》GB 18597-2023', '第4.1条', '产生危险废物的单位应当建立健全危险废物管理制度，按照国家有关规定制定危险废物管理计划，并采取有效措施防止危险废物污染环境。'),
(685, 7, '在线监测设备故障', '在线监测设备故障隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(686, 7, '环保设施运行不正常', '环保设施运行不正常隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(687, 7, '停运未报备', '停运未报备隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(688, 7, '除尘器故障', '除尘器故障隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(689, 7, '布袋除尘器破损', '布袋除尘器破损隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(690, 7, '电除尘器极板积灰', '电除尘器极板积灰隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(691, 7, '湿式除尘循环水处理不当', '湿式除尘循环水处理不当隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(692, 7, '脱硫设施不正常', '脱硫设施不正常隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(693, 7, '脱硝设施不正常', '脱硝设施不正常隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(694, 7, '烟气在线监测故障', '烟气在线监测故障隐患排查', '较大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(695, 7, 'VOCs治理不正常', 'VOCs治理不正常隐患排查', '一般', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(696, 7, '活性炭饱和未更换', '活性炭饱和未更换隐患排查', '重大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(697, 7, '污水处理不正常', '污水处理不正常隐患排查', '较大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(698, 7, '曝气系统故障', '曝气系统故障隐患排查', '一般', '《中华人民共和国环境保护法》', '第四十二条', '排放污染物的企业事业单位和其他生产经营者，应当采取措施，防治在生产建设或者其他活动中产生的废气、废水、废渣、医疗废物、粉尘、恶臭气体、放射性物质以及噪声、振动、光辐射、电磁辐射等对环境的污染和危害。排放污染物的企业事业单位和其他生产经营者，应当按照国家有关规定缴纳排污费。'),
(699, 7, '污泥脱水设备故障', '污泥脱水设备故障隐患排查', '重大', '《中华人民共和国水污染防治法》', '第十条', '排放水污染物，不得超过国家或者地方规定的水污染物排放标准和重点水污染物排放总量控制指标。'),
(700, 7, '消毒设施不正常', '消毒设施不正常隐患排查', '较大', '《中华人民共和国大气污染防治法》', '第十八条', '企业事业单位和其他生产经营者建设对大气环境有影响的项目，应当依法进行环境影响评价、公开环境影响评价文件。'),
(701, 7, '除磷设施不正常', '除磷设施不正常隐患排查', '一般', '《中华人民共和国固体废物污染环境防治法》', '第十七条', '建设产生、贮存、利用、处置固体废物的项目，应当依法进行环境影响评价，并遵守国家有关建设项目环境保护管理的规定。'),
(702, 7, '危废暂存库未防渗', '危废暂存库未防渗隐患排查', '重大', '《危险废物贮存污染控制标准》GB 18597-2023', '第4.1条', '产生危险废物的单位应当建立健全危险废物管理制度，按照国家有关规定制定危险废物管理计划，并采取有效措施防止危险废物污染环境。'),
(703, 7, '暂存库通风不良', '暂存库通风不良隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(704, 7, '暂存库消防缺失', '暂存库消防缺失隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(705, 7, '标签填写不规范', '标签填写不规范隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(706, 7, '环境应急预案不完善', '环境应急预案不完善隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(707, 7, '应急物资储备不足', '应急物资储备不足隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(708, 7, '演练未定期开展', '演练未定期开展隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(709, 7, '突发环境事件报告不及时', '突发环境事件报告不及时隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(710, 7, '信息公开不到位', '信息公开不到位隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(711, 7, '环保验收未按期完成', '环保验收未按期完成隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(712, 7, '排污证到期未续', '排污证到期未续隐患排查', '较大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(713, 7, '环评未批先建', '环评未批先建隐患排查', '一般', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(714, 7, '损害赔偿未落实', '损害赔偿未落实隐患排查', '重大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(715, 7, '环保设施风险评估缺失', '环保设施风险评估缺失隐患排查', '较大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(716, 7, '重污染应急减排执行不到位', '重污染应急减排执行不到位隐患排查', '一般', '《中华人民共和国环境保护法》', '第四十二条', '排放污染物的企业事业单位和其他生产经营者，应当采取措施，防治在生产建设或者其他活动中产生的废气、废水、废渣、医疗废物、粉尘、恶臭气体、放射性物质以及噪声、振动、光辐射、电磁辐射等对环境的污染和危害。排放污染物的企业事业单位和其他生产经营者，应当按照国家有关规定缴纳排污费。'),
(717, 7, '水源地违规建设', '水源地违规建设隐患排查', '重大', '《中华人民共和国水污染防治法》', '第十条', '排放水污染物，不得超过国家或者地方规定的水污染物排放标准和重点水污染物排放总量控制指标。'),
(718, 7, '隔离防护设施损坏', '隔离防护设施损坏隐患排查', '较大', '《中华人民共和国大气污染防治法》', '第十八条', '企业事业单位和其他生产经营者建设对大气环境有影响的项目，应当依法进行环境影响评价、公开环境影响评价文件。'),
(719, 7, '警示标识缺失', '警示标识缺失隐患排查', '一般', '《中华人民共和国固体废物污染环境防治法》', '第十七条', '建设产生、贮存、利用、处置固体废物的项目，应当依法进行环境影响评价，并遵守国家有关建设项目环境保护管理的规定。'),
(720, 7, '巡查频次不足', '巡查频次不足隐患排查', '重大', '《危险废物贮存污染控制标准》GB 18597-2023', '第4.1条', '产生危险废物的单位应当建立健全危险废物管理制度，按照国家有关规定制定危险废物管理计划，并采取有效措施防止危险废物污染环境。'),
(721, 7, '保护区内违规开发', '保护区内违规开发隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(722, 7, '生态红线内违规建设', '生态红线内违规建设隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(723, 7, '湿地保护不到位', '湿地保护不到位隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(724, 7, '生物多样性保护不足', '生物多样性保护不足隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(725, 7, '碳排放数据弄虚作假', '碳排放数据弄虚作假隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(726, 7, '温室气体监测不到位', '温室气体监测不到位隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(727, 7, '企业碳核查不配合', '企业碳核查不配合隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(728, 8, '道路路面破损', '道路路面破损隐患排查', '一般', '《中华人民共和国道路交通安全法》', '第三十条', '道路出现坍塌、坑漕、水毁、隆起等损毁或者交通信号灯、交通标志、交通标线等交通设施损毁、灭失的，道路、交通设施的养护部门或者管理部门应当设置警示标志并及时修复。'),
(729, 8, '人行道砖松动', '人行道砖松动隐患排查', '重大', '《中华人民共和国道路交通安全法》', '第一百零四条', '未经批准，擅自挖掘道路、占用道路施工或者从事其他影响道路交通安全活动的，由道路主管部门责令停止违法行为，并恢复原状，可以依法给予罚款；致使通行的人员、车辆遭受损失的，依法承担赔偿责任。'),
(730, 8, '盲道被占用', '盲道被占用隐患排查', '较大', '《公路安全保护条例》', '第二十三条', '公路管理机构、公路经营企业应当按照国务院交通运输主管部门的规定对公路进行巡查，并制作巡查记录；发现公路损毁、危及公路安全或者影响公路畅通的，应当及时设置警示标志，并采取措施组织修复或者排除险情。'),
(731, 8, '井盖缺失', '井盖缺失隐患排查', '一般', '《公路养护技术规范》JTG H10-2009', '第5.1.1条', '公路养护应贯彻"预防为主、防治结合"的方针，保持路面、路基、桥梁、隧道等设施的完好状态，保障公路安全畅通。'),
(732, 8, '井盖破损', '井盖破损隐患排查', '重大', '《公路桥涵养护规范》JTG 5120-2021', '第5.1.1条', '桥梁养护应定期进行检查和检测，及时掌握桥梁的技术状况，对发现的病害和缺陷及时进行维修加固，确保桥梁安全运营。'),
(733, 8, '路灯不亮', '路灯不亮隐患排查', '较大', '《公路隧道养护技术规范》JTG H12-2015', '第4.1.1条', '隧道养护应定期进行检查和检测，掌握隧道的技术状况，及时发现和处理病害。隧道检查分为经常检查、定期检查和特殊检查。'),
(734, 8, '路灯杆倾斜', '路灯杆倾斜隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(735, 8, '交通信号灯不亮', '交通信号灯不亮隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(736, 8, '交通标志倾斜', '交通标志倾斜隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(737, 8, '路牌字迹模糊', '路牌字迹模糊隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(738, 8, '公交站台破损', '公交站台破损隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(739, 8, '候车亭玻璃破损', '候车亭玻璃破损隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(740, 8, '公共座椅损坏', '公共座椅损坏隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(741, 8, '公厕设施损坏', '公厕设施损坏隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(742, 8, '水龙头损坏', '水龙头损坏隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(743, 8, '冲水阀失灵', '冲水阀失灵隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(744, 8, '门锁损坏', '门锁损坏隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(745, 8, '照明故障', '照明故障隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(746, 8, '健身器材损坏', '健身器材损坏隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(747, 8, '儿童游乐设施损坏', '儿童游乐设施损坏隐患排查', '重大', '《中华人民共和国道路交通安全法》', '第三十条', '道路出现坍塌、坑漕、水毁、隆起等损毁或者交通信号灯、交通标志、交通标线等交通设施损毁、灭失的，道路、交通设施的养护部门或者管理部门应当设置警示标志并及时修复。'),
(748, 8, '滑梯破损', '滑梯破损隐患排查', '较大', '《中华人民共和国道路交通安全法》', '第一百零四条', '未经批准，擅自挖掘道路、占用道路施工或者从事其他影响道路交通安全活动的，由道路主管部门责令停止违法行为，并恢复原状，可以依法给予罚款；致使通行的人员、车辆遭受损失的，依法承担赔偿责任。'),
(749, 8, '秋千链条断裂', '秋千链条断裂隐患排查', '一般', '《公路安全保护条例》', '第二十三条', '公路管理机构、公路经营企业应当按照国务院交通运输主管部门的规定对公路进行巡查，并制作巡查记录；发现公路损毁、危及公路安全或者影响公路畅通的，应当及时设置警示标志，并采取措施组织修复或者排除险情。'),
(750, 8, '摇椅松动', '摇椅松动隐患排查', '重大', '《公路养护技术规范》JTG H10-2009', '第5.1.1条', '公路养护应贯彻"预防为主、防治结合"的方针，保持路面、路基、桥梁、隧道等设施的完好状态，保障公路安全畅通。'),
(751, 8, '绿化树木枯死', '绿化树木枯死隐患排查', '较大', '《公路桥涵养护规范》JTG 5120-2021', '第5.1.1条', '桥梁养护应定期进行检查和检测，及时掌握桥梁的技术状况，对发现的病害和缺陷及时进行维修加固，确保桥梁安全运营。'),
(752, 8, '绿化带护栏破损', '绿化带护栏破损隐患排查', '一般', '《公路隧道养护技术规范》JTG H12-2015', '第4.1.1条', '隧道养护应定期进行检查和检测，掌握隧道的技术状况，及时发现和处理病害。隧道检查分为经常检查、定期检查和特殊检查。'),
(753, 8, '绿化带缺株断带', '绿化带缺株断带隐患排查', '重大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(754, 8, '行道树倾斜', '行道树倾斜隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(755, 8, '树枝过低影响通行', '树枝过低影响通行隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(756, 8, '景观灯损坏', '景观灯损坏隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(757, 8, '喷泉设备故障', '喷泉设备故障隐患排查', '较大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(758, 8, '景观水池水质恶化', '景观水池水质恶化隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(759, 8, '灌溉系统故障', '灌溉系统故障隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(760, 8, '园林排水不畅', '园林排水不畅隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(761, 8, '广场砖破损', '广场砖破损隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(762, 8, '广场台阶破损', '广场台阶破损隐患排查', '重大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(763, 8, '广场护栏松动', '广场护栏松动隐患排查', '较大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(764, 8, '广场照明不足', '广场照明不足隐患排查', '一般', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(765, 8, '广场排水不畅', '广场排水不畅隐患排查', '重大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(766, 8, '公共垃圾桶破损', '公共垃圾桶破损隐患排查', '较大', '《中华人民共和国道路交通安全法》', '第三十条', '道路出现坍塌、坑漕、水毁、隆起等损毁或者交通信号灯、交通标志、交通标线等交通设施损毁、灭失的，道路、交通设施的养护部门或者管理部门应当设置警示标志并及时修复。'),
(767, 8, '垃圾桶外溢', '垃圾桶外溢隐患排查', '一般', '《中华人民共和国道路交通安全法》', '第一百零四条', '未经批准，擅自挖掘道路、占用道路施工或者从事其他影响道路交通安全活动的，由道路主管部门责令停止违法行为，并恢复原状，可以依法给予罚款；致使通行的人员、车辆遭受损失的，依法承担赔偿责任。'),
(768, 8, '垃圾收集点异味', '垃圾收集点异味隐患排查', '重大', '《公路安全保护条例》', '第二十三条', '公路管理机构、公路经营企业应当按照国务院交通运输主管部门的规定对公路进行巡查，并制作巡查记录；发现公路损毁、危及公路安全或者影响公路畅通的，应当及时设置警示标志，并采取措施组织修复或者排除险情。'),
